"""Batch 6 (final): rememberIt / studentQuestions / formulas for ALL remaining concepts."""
import json, os, glob

ROOT = os.path.join(os.path.dirname(__file__), "..", "content-packs")
INDEX = {}
for f in glob.glob(os.path.join(ROOT, "*", "concepts", "*.json")):
    INDEX[os.path.basename(f)[:-5]] = f

def R(hook, unpack):
    return {"hook": hook, "unpack": unpack}
def Q(*pairs):
    return [{"q": q, "a": a} for q, a in pairs]

