changed = missing = 0
for cid, fields in DATA.items():
    path = INDEX.get(cid)
    if not path:
        print("MISSING:", cid); missing += 1; continue
    with open(path, "r", encoding="utf-8") as f:
        c = json.load(f)
    for k, v in fields.items():
        c[k] = v
    with open(path, "w", encoding="utf-8") as f:
        json.dump(c, f, ensure_ascii=False, indent=2)
    changed += 1

print("DONE changed=%d missing=%d total_in_data=%d" % (changed, missing, len(DATA)))
